import (
	"errors"
	"time"

	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
// Security: Implements timeout protection to prevent infinite loops and resource exhaustion.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	// Create VM once outside the loop for better performance
	vm := otto.New()

	// Set a reasonable timeout for script execution (configurable)
	timeout := 5 * time.Second

	for _, item := range items {
		// Inject the current item as a global variable named 'item'
		err := vm.Set("item", item)
		if err != nil {
			return nil, err
		}

		// Execute script with timeout protection
		boolResult, err := executeScriptWithTimeout(vm, conditionScript, timeout)
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

// executeScriptWithTimeout runs a script with a timeout to prevent infinite loops
func executeScriptWithTimeout(vm *otto.Otto, script string, timeout time.Duration) (bool, error) {
	// Channel to receive the result
	type scriptResult struct {
		value bool
		err   error
	}
	resultChan := make(chan scriptResult, 1)

	// Set up interrupt mechanism
	vm.Interrupt = make(chan func(), 1)

	// Execute script in a goroutine
	go func() {
		value, err := vm.Run(script)
		if err != nil {
			resultChan <- scriptResult{false, err}
			return
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		resultChan <- scriptResult{boolResult, err}
	}()

	// Wait for result or timeout
	select {
	case result := <-resultChan:
		return result.value, result.err
	case <-time.After(timeout):
		// Interrupt the VM
		vm.Interrupt <- func() {
			panic("script execution timeout")
		}
		// Wait a bit for the interrupt to take effect
		select {
		case <-resultChan:
			// Script was interrupted
		case <-time.After(100 * time.Millisecond):
			// Interrupt didn't work in time
		}
		return false, errors.New("script execution timeout exceeded")
	}
}

