			defer func() {
				timer.Stop()
				if caught := recover(); caught != nil {
					err = fmt.Errorf("script execution error: %v", caught)
				}
			}()
			return vm.Run(conditionScript)
		}()

		if err != nil {
			return nil, fmt.Errorf("script execution failed: %w", err)
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
