package main

import (
	"context"
	"errors"
	"fmt"
	"time"

	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
//
// Security improvements:
// - Execution timeout to prevent infinite loops
// - Panic recovery to handle runtime errors
// - Single VM instance with proper cleanup between iterations
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	return FilterItemsWithTimeout(conditionScript, items, 5*time.Second)
}

// FilterItemsWithTimeout filters items with a configurable timeout per script execution.
func FilterItemsWithTimeout(conditionScript string, items []map[string]interface{}, timeout time.Duration) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	// Create a single VM instance for better performance
	vm := otto.New()

	// Disable some dangerous features if needed
	// Note: otto has limited security controls, but we add timeout protection

	for i, item := range items {
		// Create a context with timeout for this iteration
		ctx, cancel := context.WithTimeout(context.Background(), timeout)

		// Set up interrupt channel for timeout
		interruptChan := make(chan func(), 1)
		vm.Interrupt = interruptChan

		// Goroutine to handle timeout
		done := make(chan bool, 1)
		go func() {
			select {
			case <-ctx.Done():
				vm.Interrupt <- func() {
					panic(fmt.Sprintf("script execution timeout after %v", timeout))
				}
			case <-done:
				return
			}
		}()

		// Execute with panic recovery
		boolResult, err := func() (result bool, err error) {
			defer func() {
				if caught := recover(); caught != nil {
					err = fmt.Errorf("script execution failed for item %d: %v", i, caught)
				}
				done <- true
				cancel() // Always cancel the context
			}()

			// Inject the current item as a global variable named 'item'
			if setErr := vm.Set("item", item); setErr != nil {
				return false, fmt.Errorf("failed to set item variable: %w", setErr)
			}

			// Run the condition script
			value, runErr := vm.Run(conditionScript)
			if runErr != nil {
				return false, fmt.Errorf("script execution error: %w", runErr)
			}

			// Convert result to boolean using JavaScript truthiness
			boolVal, boolErr := value.ToBoolean()
			if boolErr != nil {
				return false, fmt.Errorf("failed to convert result to boolean: %w", boolErr)
			}

			return boolVal, nil
		}()

		// Clean up
		cancel()

		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

// SafeFilterItems provides additional safety by validating the script before execution
func SafeFilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	// Validate script is not empty
	if conditionScript == "" {
		return nil, errors.New("condition script cannot be empty")
	}

	// Optional: Add script length limit to prevent extremely large scripts
	const maxScriptLength = 10000
	if len(conditionScript) > maxScriptLength {
		return nil, fmt.Errorf("script exceeds maximum length of %d characters", maxScriptLength)
	}

	// Test compile the script first with an empty VM
	testVM := otto.New()
	if _, err := testVM.Run(conditionScript); err != nil {
		return nil, fmt.Errorf("script compilation failed: %w", err)
	}

	return FilterItemsWithTimeout(conditionScript, items, 5*time.Second)
}

