// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
//
// Security improvements:
// - Implements timeout protection to prevent infinite loops and DoS attacks
// - Uses interrupt mechanism to halt long-running scripts
// - Default timeout of 5 seconds per script execution
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	return FilterItemsWithTimeout(conditionScript, items, 5*time.Second)
}

// FilterItemsWithTimeout filters items with a configurable timeout per script execution.
func FilterItemsWithTimeout(conditionScript string, items []map[string]interface{}, timeout time.Duration) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	// Create VM once for better performance
	vm := otto.New()

	for _, item := range items {
		// Inject the current item as a global variable named 'item'
		err := vm.Set("item", item)
		if err != nil {
			return nil, err
		}

		// Execute script with timeout protection
		boolResult, err := executeScriptWithTimeout(vm, conditionScript, timeout)
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

// executeScriptWithTimeout runs a script with timeout protection to prevent DoS attacks.
func executeScriptWithTimeout(vm *otto.Otto, script string, timeout time.Duration) (bool, error) {
	// Channel to communicate results
	type result struct {
		value bool
		err   error
	}
	resultChan := make(chan result, 1)

	// Start a timer for the timeout
	timer := time.NewTimer(timeout)
	defer timer.Stop()

	// Set up interrupt mechanism
	go func() {
		<-timer.C
		vm.Interrupt <- func() {
			panic("script execution timeout")
		}
	}()

	// Execute script in a goroutine
	go func() {
		defer func() {
			if caught := recover(); caught != nil {
				resultChan <- result{
					value: false,
					err:   errors.New("script execution interrupted or panicked"),
				}
			}
		}()

		value, err := vm.Run(script)
		if err != nil {
			resultChan <- result{value: false, err: err}
			return
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		resultChan <- result{value: boolResult, err: err}
	}()

	// Wait for either completion or timeout
	select {
	case res := <-resultChan:
		return res.value, res.err
	case <-timer.C:
		return false, errors.New("script execution timeout exceeded")
	}
}

